import { useState } from "react";
import axios from "axios";

const API_BASE = "http://localhost:8000";

export default function AdminFood() {
  const [foodName, setFoodName] = useState("");
  const [category, setCategory] = useState("");
  const [image, setImage] = useState(null);
  const [preview, setPreview] = useState(null);
  const [loading, setLoading] = useState(false);

  const handleImageChange = (e) => {
    const file = e.target.files[0];
    setImage(file);
    if (file) setPreview(URL.createObjectURL(file));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();

    if (!foodName || !category || !image) {
      alert("Please fill all fields");
      return;
    }

    const formData = new FormData();
    formData.append("name", foodName);
    formData.append("category", category);
    formData.append("image", image);

    try {
      setLoading(true);
      await axios.post(`${API_BASE}/api/food/`, formData, {
        headers: { "Content-Type": "multipart/form-data" },
      });

      alert("Food item added successfully ✅");

      setFoodName("");
      setCategory("");
      setImage(null);
      setPreview(null);
    } catch (err) {
      console.error(err);
      alert("Failed to add food ❌");
    } finally {
      setLoading(false);
    }
  };

  return (
    <>
      <style>{`
        .admin-container {
          max-width: 600px;
          margin: 40px auto;
          padding: 30px;
          background: rgba(20, 18, 18, 0.6);
          backdrop-filter: blur(12px);
          border-radius: 18px;
          color: #fff;
        }
        .admin-title {
          margin-bottom: 25px;
          color: #d4af7a;
          text-align: center;
        }
        .form-group { margin-bottom: 18px; }
        .form-group label {
          display: block;
          margin-bottom: 6px;
          font-size: 14px;
        }
        .form-group input,
        .form-group select {
          width: 100%;
          padding: 12px;
          border-radius: 10px;
          border: none;
        }
        .image-preview img {
          width: 140px;
          height: 140px;
          object-fit: cover;
          border-radius: 12px;
          border: 2px solid #b88a5a;
        }
        .btn-primary {
          width: 100%;
          padding: 14px;
          background: linear-gradient(135deg, #b88a5a, #e0c097);
          border: none;
          border-radius: 12px;
          font-weight: 600;
          cursor: pointer;
        }
      `}</style>

      <div className="admin-container">
        <h2 className="admin-title">Add Food Item</h2>

        <form onSubmit={handleSubmit}>
          <div className="form-group">
            <label>Food Name</label>
            <input value={foodName} onChange={(e) => setFoodName(e.target.value)} />
          </div>

          <div className="form-group">
            <label>Category</label>
            <select value={category} onChange={(e) => setCategory(e.target.value)}>
              <option value="">Select</option>
              <option value="bread">Bread</option>
              <option value="drinks">Drinks</option>
              <option value="veg">Veg</option>
              <option value="non-veg">Non Veg</option>
              <option value="dessert">Dessert</option>
            </select>
          </div>

          <div className="form-group">
            <label>Food Image</label>
            <input type="file" accept="image/*" onChange={handleImageChange} />
          </div>

          {preview && <div className="image-preview"><img src={preview} /></div>}

          <button className="btn-primary" type="submit" disabled={loading}>
            {loading ? "Adding..." : "Add Food"}
          </button>
        </form>
      </div>
    </>
  );
}
